import{_ as t,o as s,c as a,ag as r}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"UI overview","description":"","frontmatter":{"title":"UI overview","lang":"en-US"},"headers":[],"relativePath":"ui-overview.md","filePath":"ui-overview.md","lastUpdated":1782558072000}'),o={name:"ui-overview.md"};function i(n,e,l,d,c,u){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ui-overview" tabindex="-1">UI overview <a class="header-anchor" href="#ui-overview" aria-label="Permalink to &quot;UI overview&quot;">​</a></h1><p>The Piwi Dashboard is a single-page application built with <a href="https://ui.nuxt.com" target="_blank" rel="noreferrer">Nuxt UI</a>. It uses a sidebar navigation layout with real-time updates via Server-Sent Events — pages refresh automatically when test runs start or finish, without requiring manual reload.</p><h2 id="inline-help" tabindex="-1">Inline help <a class="header-anchor" href="#inline-help" aria-label="Permalink to &quot;Inline help&quot;">​</a></h2><p>Throughout the dashboard, blocks that aren&#39;t self-explanatory carry a small muted help icon (a circled question mark) next to their title. Click it for a short explanation of the feature and, where available, a <strong>Learn more</strong> link to the relevant documentation page. The icon is keyboard-focusable and the popover closes with <code>Esc</code>. Self-explanatory blocks (counters, search boxes, basic forms) intentionally have no icon, keeping the interface uncluttered.</p><h2 id="navigation-structure" tabindex="-1">Navigation structure <a class="header-anchor" href="#navigation-structure" aria-label="Permalink to &quot;Navigation structure&quot;">​</a></h2><p>The dashboard sidebar provides access to the main sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Home</td><td><code>/</code></td><td>Landing page with aggregate statistics and activity overview</td></tr><tr><td>Projects</td><td><code>/projects</code></td><td>Full project listing with search, filters, and actions</td></tr><tr><td>Settings</td><td><code>/settings</code></td><td>Application configuration (general, users, storage, tags)</td></tr><tr><td>API Docs</td><td><code>/docs</code></td><td>Interactive API reference auto-generated from the OpenAPI 3.1 spec — browse all endpoints, request/response schemas, and run live requests</td></tr></tbody></table><p>Project-level pages are accessed by clicking into a specific project:</p><table tabindex="0"><thead><tr><th>Page</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Project detail</td><td><code>/projects/:id</code></td><td>Run history, failure clusters, flaky tests, trends, test cases, run comparison</td></tr><tr><td>Project edit</td><td><code>/projects/:id/edit</code></td><td>Edit project label, description, tags, and AI diagnosis instructions</td></tr><tr><td>Performance</td><td><code>/projects/:id/performance</code></td><td>Duration trends, slowest tests, run comparison</td></tr><tr><td>Test cases</td><td><code>/projects/:id/test-cases</code></td><td>All unique test cases with per-case history</td></tr><tr><td>Failure cluster</td><td><code>/failure-clusters/:id</code></td><td>Cluster details, affected tests, AI diagnosis, and triage</td></tr></tbody></table><p>Individual run and test case pages:</p><table tabindex="0"><thead><tr><th>Page</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td>Test run</td><td><code>/test-runs/:id</code></td><td>Full detail of a single run — test list, errors, reports, traces</td></tr><tr><td>Test case</td><td><code>/test-cases/:id</code></td><td>Single test details — steps, web vitals, network requests</td></tr></tbody></table><h2 id="home-page" tabindex="-1">Home page <a class="header-anchor" href="#home-page" aria-label="Permalink to &quot;Home page&quot;">​</a></h2><p>The home page provides a quick health check across all projects:</p><ul><li><strong>Stats cards</strong> — total projects, total runs, active projects, passing projects, flaky test count, and slowest project</li><li><strong>Test results trend chart</strong> — stacked area chart showing pass/fail/skip/flaky distribution over time</li><li><strong>Recent projects</strong> — quick links to the most recently active projects with their current status</li><li><strong>Getting started</strong> — API usage example for teams that haven&#39;t configured the reporter yet</li></ul><h2 id="projects-page" tabindex="-1">Projects page <a class="header-anchor" href="#projects-page" aria-label="Permalink to &quot;Projects page&quot;">​</a></h2><p>The projects page is the primary navigation hub:</p><ul><li><strong>Search</strong> — filter projects by name with an instant text search</li><li><strong>Tag filters</strong> — click tag badges to show only projects with specific tags</li><li><strong>Table columns</strong> — project name (with tags), run count, last run date, duration, status badge, test status bar, report links, and action buttons</li><li><strong>New project</strong> — create a project manually with name, label, description, and tags</li><li><strong>Refresh</strong> — manually trigger a data refresh (also happens automatically via SSE)</li></ul><h2 id="project-detail" tabindex="-1">Project detail <a class="header-anchor" href="#project-detail" aria-label="Permalink to &quot;Project detail&quot;">​</a></h2><p>Shows the complete run history for a single project, with six tabs:</p><ul><li><strong>Test runs</strong> — each row shows run status, start time, duration, test counts, browser badges, and links to reports/traces; select two runs to compare them</li><li><strong>Failure clusters</strong> — all unique failure signatures across all runs, with status, error type, occurrence count, AI diagnosis badge, and a link to the cluster detail page</li><li><strong>Flaky tests</strong> — tests that fail intermittently, scored by a composite flakiness metric; shows failure rate, retry passes, status alternation count, root cause classification, and impact score (wasted CI minutes); sortable and filterable by root cause</li><li><strong>Trends</strong> — duration trend chart with date filter, and a slowest-tests table</li><li><strong>Test cases</strong> — all unique test cases with status, pass rate, result breakdown (with icons), average duration, and last run date</li><li><strong>Compare</strong> — side-by-side delta view between two selected runs (new failures, recovered, duration changes)</li></ul><h2 id="performance-page" tabindex="-1">Performance page <a class="header-anchor" href="#performance-page" aria-label="Permalink to &quot;Performance page&quot;">​</a></h2><p>Provides insights into test execution speed:</p><ul><li><strong>Duration trend chart</strong> — line chart showing average and P90 run durations over time</li><li><strong>Slowest tests table</strong> — top 20 test cases ranked by average duration, with min/max and occurrence count</li><li><strong>Run comparison</strong> — select two runs to see a side-by-side delta view showing which tests improved, regressed, or stayed unchanged</li></ul><h2 id="test-run-detail" tabindex="-1">Test run detail <a class="header-anchor" href="#test-run-detail" aria-label="Permalink to &quot;Test run detail&quot;">​</a></h2><p>Deep dive into a single test execution:</p><ul><li><strong>Summary header</strong> — status, duration, start time, test counts, duration metrics (Avg P90), and metadata blocks (CI/Environment, Source control, Tags/Other) in a responsive card grid</li><li><strong>Live progress</strong> — if the run is still in progress (<code>running</code> status), a live progress bar and streaming test results appear in real time</li><li><strong>Reports</strong> — buttons to open attached HTML reports (Playwright, Monocart) in a new tab or download blob archives</li><li><strong>Tabbed right panel</strong> with five tabs: <ul><li><strong>Test cases</strong> — every test with browser icon (first column), status, duration, file location, error messages, annotation badges, traces; scrollable table with sticky header, searchable, filterable by status and browser, and paginated</li></ul></li><li><strong>Tree</strong> — tests grouped by suite hierarchy (describe blocks), with expandable/collapsible nodes that show suite mode badges, annotation counts, and per-suite aggregate statistics <ul><li><strong>Workers</strong> — horizontal timeline showing worker assignment per test case; click a bar to jump to that test case in the table</li><li><strong>Compare</strong> — select a baseline run for side-by-side delta view showing new failures, recovered tests, and duration changes (improved/regressed/unchanged)</li><li><strong>Slow endpoints</strong> — aggregated network request table showing slow API calls grouped by method + normalized route, with avg/p90/max duration and error rate</li><li><strong>Failure groups</strong> — failures grouped by root cause via error fingerprinting; each group shows signature, error type, count, flaky/worker-correlation signals, known-since run, and actions: filter the test list, trigger AI diagnosis (opens a modal), or navigate to the cluster detail page</li></ul></li><li><strong>Delete</strong> — administrators can delete the entire run and associated files</li></ul><h2 id="test-case-detail" tabindex="-1">Test case detail <a class="header-anchor" href="#test-case-detail" aria-label="Permalink to &quot;Test case detail&quot;">​</a></h2><p>Shows everything about a single test execution:</p><ul><li><strong>Status card</strong> — test ID, title, location (copyable), duration, worker index, retries, slowest step, and duration vs historical average comparison</li><li><strong>Run context</strong> — environment, CI provider, build number, branch, commit, author, browser, viewport — all from the parent test run&#39;s metadata</li><li><strong>HTML report</strong> — direct link to the specific test in the full HTML report (with screenshots, video, and interactive trace viewer)</li><li><strong>Traces</strong> — attached trace files with &quot;View trace&quot; buttons that open them in the Playwright trace viewer (trace.playwright.dev), plus download buttons; while the parent run is still in progress, traces and attachments appear live as soon as each test uploads them</li><li><strong>Error details</strong> — full error message with copy button and expandable view for long errors; if the test belongs to a failure cluster, a context row shows how many other tests in the same run share the same root cause</li><li><strong>Performance hints</strong> — actionable suggestions for slow navigations, flaky tests, slow assertions, and long step sequences</li><li><strong>Steps</strong> — execution steps with category badges and individual timing</li><li><strong>Web Vitals</strong> — TTFB, FCP, DOMContentLoaded, etc. with color-coded thresholds (green/amber/red)</li><li><strong>Network requests</strong> — all HTTP requests grouped by method + normalized route with count and avg duration; backend server logs (captured via the <code>X-Piwi-Logs</code> header by ASP.NET Core or Nitro integrations) are shown inline under each request</li><li><strong>History</strong> — line chart and table showing this test case&#39;s status and duration across all previous runs</li></ul><h2 id="settings-pages" tabindex="-1">Settings pages <a class="header-anchor" href="#settings-pages" aria-label="Permalink to &quot;Settings pages&quot;">​</a></h2><h3 id="general-settings" tabindex="-1">General settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General settings&quot;">​</a></h3><p>Basic application configuration. In demo mode, includes a &quot;Reset Demo&quot; button to restore seed data.</p><h3 id="users-settings-users" tabindex="-1">Users (<code>/settings/users</code>) <a class="header-anchor" href="#users-settings-users" aria-label="Permalink to &quot;Users (`/settings/users`)&quot;">​</a></h3><p>Available when authentication is enabled (or shown with an informational message when disabled):</p><ul><li><strong>User table</strong> — username, display name, role, and creation date</li><li><strong>Add user</strong> — create accounts with username, password, role (administrator/reporter/user), and display name</li><li><strong>API keys</strong> — generate and manage API keys for CI authentication; keys are shown once at creation and stored hashed</li></ul><h3 id="storage-settings-storage" tabindex="-1">Storage (<code>/settings/storage</code>) <a class="header-anchor" href="#storage-settings-storage" aria-label="Permalink to &quot;Storage (`/settings/storage`)&quot;">​</a></h3><p>Storage statistics and maintenance tools:</p><ul><li><strong>Stats</strong> — total projects, test runs, test cases, traces, stored reports, aggregate report size, and on-disk storage size</li><li><strong>Cleanup</strong> — bulk-delete test runs older than a configurable period (7 to 365 days) with a confirmation dialog</li></ul><h3 id="tags-settings-tags" tabindex="-1">Tags (<code>/settings/tags</code>) <a class="header-anchor" href="#tags-settings-tags" aria-label="Permalink to &quot;Tags (`/settings/tags`)&quot;">​</a></h3><p>Manage tags used to organize projects:</p><ul><li><strong>Tag table</strong> — tag text, color, and creation date</li><li><strong>Add tag</strong> — create new tags with custom names and colors</li><li><strong>Edit/Delete</strong> — modify or remove existing tags (administrator only)</li></ul><h3 id="ai-diagnosis-settings-ai" tabindex="-1">AI diagnosis (<code>/settings/ai</code>) <a class="header-anchor" href="#ai-diagnosis-settings-ai" aria-label="Permalink to &quot;AI diagnosis (`/settings/ai`)&quot;">​</a></h3><p>Configure LLM-based failure analysis:</p><ul><li><strong>Provider</strong> — choose Anthropic API or an OpenAI-compatible endpoint (Ollama, LM Studio, OpenRouter, Groq, Together AI, Mistral AI, or any custom URL)</li><li><strong>API key / model / base URL</strong> — provider credentials and model selection; keys are stored in the database (admin-only) or via <code>PIWI_AI_*</code> environment variables</li><li><strong>Auto-diagnose</strong> — automatically run AI diagnosis on new failure clusters when a run finishes (max 3 per run)</li><li><strong>Global analysis instructions</strong> — persistent text appended to the system prompt for every diagnosis across all projects; use this for general preferences, output format requirements, or team conventions (e.g. &quot;always recommend checking retry counts before concluding flakiness&quot;)</li><li><strong>Diagnosis context limits</strong> — caps on how much evidence is packed into each diagnosis (error text, SCM patch budget, affected tests, steps, console entries, network requests, ARIA snapshot, test source), letting you trade detail against token cost. Leave a field empty to use its default. Any limit can instead be pinned via a <code>PIWI_AI_MAX_*</code> environment variable, in which case it takes precedence and shows read-only.</li><li><strong>Environment variables</strong> — copy-to-clipboard snippet for <code>PIWI_AI_*</code> env vars when credentials should not be stored in the database</li></ul><h2 id="failure-cluster-detail" tabindex="-1">Failure cluster detail <a class="header-anchor" href="#failure-cluster-detail" aria-label="Permalink to &quot;Failure cluster detail&quot;">​</a></h2><p>Each failure cluster has a dedicated page (<code>/failure-clusters/:id</code>) with three tabs:</p><ul><li><strong>Overview</strong> — signature, error type, selector, occurrence count, first/last seen runs, sample raw error, and list of affected test cases with their latest run status</li><li><strong>Triage</strong> — set cluster status (open / resolved / ignored) and write an internal triage note</li><li><strong>AI diagnosis</strong> — run an LLM diagnosis of the cluster with full control over the context sent to the LLM: <ul><li><strong>Baseline commit picker</strong> — select the commit to compare against so the diagnosis includes the relevant SCM diff; pin a commit to persist it for all future diagnoses of this cluster</li><li><strong>Commit browser</strong> — &quot;Browse commits&quot; opens a split modal where you can check specific commits to include their full diffs in the LLM context, regardless of the baseline; useful when the relevant change isn&#39;t the most recent one; the modal shows file-level diffs with syntax-colored patch lines and aggregates stats (files changed, lines added/removed) for your selection</li><li><strong>Diagnosis result</strong> — category, confidence, summary, root cause, evidence list, suggested fix, and prevention tips; re-run at any time to refresh after new occurrences</li></ul></li></ul><h3 id="per-project-ai-instructions" tabindex="-1">Per-project AI instructions <a class="header-anchor" href="#per-project-ai-instructions" aria-label="Permalink to &quot;Per-project AI instructions&quot;">​</a></h3><p>In the project edit page (<code>/projects/:id/edit</code>), an <strong>AI diagnosis instructions</strong> field lets you provide project-specific context that is combined with the global instructions for every diagnosis of that project&#39;s clusters. Use this to describe the system under test, known failure patterns, or domain-specific remediation guidance.</p><h2 id="real-time-updates" tabindex="-1">Real-time updates <a class="header-anchor" href="#real-time-updates" aria-label="Permalink to &quot;Real-time updates&quot;">​</a></h2><p>The dashboard uses Server-Sent Events (SSE) for live updates:</p><ol><li><strong>Global stream</strong> (<code>/api/stream</code>) — notifies all connected clients when a run starts, finishes, or is submitted. Pages automatically refresh their data.</li><li><strong>Per-run stream</strong> (<code>/api/test-runs/:id/stream</code>) — used on the test run detail page to show live progress as tests complete during a streaming run.</li></ol><p>This means you never need to manually refresh the dashboard — it updates itself whenever CI submits new results.</p><h2 id="demo-run-simulator" tabindex="-1">Demo run simulator <a class="header-anchor" href="#demo-run-simulator" aria-label="Permalink to &quot;Demo run simulator&quot;">​</a></h2><p>The <a href="https://piwitests.github.io/demo/" target="_blank" rel="noreferrer">live demo</a> includes a <strong>Simulate a test run</strong> menu in the demo banner. It replays the exact streaming protocol a Piwi reporter speaks during a real Playwright run — entirely in your browser — so you can watch a run arrive live. Available scenarios:</p><ul><li><strong>Passing run</strong> — all tests pass across 4 parallel workers</li><li><strong>Run with failures</strong> — failures joining a known failure cluster, plus a brand-new cluster</li><li><strong>Flaky retries</strong> — tests that fail and then pass on retry</li><li><strong>Performance regression</strong> — a green run that is ~2× slower, with degraded endpoints</li><li><strong>Interrupted run</strong> — a CI job killed partway through the suite</li><li><strong>Cross-browser run</strong> — tests distributed across Chromium, Firefox, and WebKit to showcase the browser column and filter</li></ul><p>Each simulation creates a real run in the in-browser database: initialization status, live per-test updates, worker timeline, failure groups, regression context, and history-based comparisons all behave exactly as they would against a real server.</p><h2 id="demo-user-switcher-act-as" tabindex="-1">Demo user switcher (act as) <a class="header-anchor" href="#demo-user-switcher-act-as" aria-label="Permalink to &quot;Demo user switcher (act as)&quot;">​</a></h2><p>The demo runs with authentication conceptually <strong>enabled</strong> so the role-based and project-affectation features are fully explorable. Use the <strong>Acting as</strong> picker in the demo banner to switch between several pre-seeded identities:</p><ul><li><strong>Avery (Admin)</strong> — full access to every project; sees the user management and project members screens</li><li><strong>Robin (CI Reporter)</strong> — global access; can submit/triage but not manage users</li><li><strong>Sam (Checkout team)</strong> — a <code>user</code> scoped to a single project</li><li><strong>Priya (API &amp; UI team)</strong> — a <code>user</code> scoped to two projects</li><li><strong>Noah (No projects yet)</strong> — a <code>user</code> with no affectations (sees an empty dashboard until assigned)</li></ul><p>Switching identity reloads the dashboard under the new user, so the project list, sidebar menu, dashboard overview, recent runs, and search all reflect that user&#39;s <strong>project affectations</strong>. Acting as the admin, you can change affectations live — from <strong>Settings → User management → Project access</strong> (per user) or a project&#39;s <strong>Members</strong> tab (per project) — then switch to that user to see the effect. All of this happens entirely in your browser.</p><h2 id="responsive-design" tabindex="-1">Responsive design <a class="header-anchor" href="#responsive-design" aria-label="Permalink to &quot;Responsive design&quot;">​</a></h2><p>The dashboard is fully responsive:</p><ul><li><strong>Desktop</strong> — sidebar navigation with full table views</li><li><strong>Tablet</strong> — collapsible sidebar, tables scroll horizontally</li><li><strong>Mobile</strong> — compact layout with stacked cards and hamburger menu</li></ul><h2 id="dark-mode" tabindex="-1">Dark mode <a class="header-anchor" href="#dark-mode" aria-label="Permalink to &quot;Dark mode&quot;">​</a></h2><p>The dashboard supports light and dark themes, following the system preference by default. Toggle manually via the theme switcher in the sidebar.</p>',66)])])}const p=t(o,[["render",i]]);export{h as __pageData,p as default};
